// onchain-snapshotter — normalize sources into snapshot rows. TWO CLOCKS (DB-SCHEMA §1/§8):
//  dash-platform (platform-explorer): hourly state, ts=fetch, height=PE block   -> APPEND (DO NOTHING)
//  zec_block_height (blockchair):      hourly chain-tip, ts=block time, height=height -> APPEND
//  zec supply (ZecHub):                DAILY date-keyed aggregate, ts=close-date UTC midnight,
//                                      height NULL, revisable intraday                 -> UPSERT
const fetchTs = Date.now();
const hourBucket = (t) => Math.floor(t / 3600000) * 3600000;

const status = $('PE status').first().json || {};
const shielded = $('PE shielded').first().json || {};

// blockchair /zcash/stats is application/json -> parsed; tolerate node failure (continueRegularOutput).
let bc = {};
try { bc = (($('Zcash tip').first().json) || {}).data || {}; } catch (e) { bc = {}; }

// ZecHub is served text/plain -> unparsed under json.data; parse + take the newest close element.
function zecLast(nodeName) {
  const j = $(nodeName).first().json;
  let arr = j;
  if (j && typeof j.data === 'string') { try { arr = JSON.parse(j.data); } catch (e) { return null; } }
  else if (j && Array.isArray(j.data)) arr = j.data;
  if (!Array.isArray(arr)) return null;
  return arr.length ? arr[arr.length - 1] : null;
}
const zs = zecLast('ZecHub shielded');
const zt = zecLast('ZecHub total');

// close 'MM/DD/YYYY' -> epoch-ms UTC midnight of that date (the datum's true day).
function closeToTs(close) {
  if (typeof close !== 'string') return null;
  const p = close.split('/');
  if (p.length !== 3) return null;
  const mm = Number(p[0]), dd = Number(p[1]), yy = Number(p[2]);
  if (!Number.isFinite(mm) || !Number.isFinite(dd) || !Number.isFinite(yy)) return null;
  return Date.UTC(yy, mm - 1, dd);
}
// blockchair 'YYYY-MM-DD HH:MM:SS' (UTC) -> epoch-ms.
function bcTimeToTs(t) {
  if (typeof t !== 'string') return null;
  const ms = Date.parse(t.replace(' ', 'T') + 'Z');
  return Number.isFinite(ms) ? ms : null;
}

const peHeight = (status && status.api && status.api.block && Number.isFinite(status.api.block.height)) ? status.api.block.height : null;

const append = [];   // DO NOTHING (immutable hourly observations)
const upsert = [];   // DO UPDATE (daily aggregate, converges to ZecHub's latest value)
const dropped = [];

function mkRow(source, asset, metric, valueRaw, valueNum, height, ts, raw) {
  // Guard: never coerce undefined/null into the string 'undefined' for NOT NULL value_raw.
  if (valueRaw === undefined || valueRaw === null) { dropped.push(metric); return null; }
  if (!Number.isFinite(ts)) { dropped.push(metric + ':bad-ts'); return null; }
  const n = (valueNum === null || valueNum === undefined || Number.isNaN(Number(valueNum))) ? null : Number(valueNum);
  return {
    ts, ts_bucket: hourBucket(ts), source, asset, metric,
    value_raw: String(valueRaw),
    value_num: n,
    height: (height === null || height === undefined) ? null : height,
    raw_json: raw === undefined ? null : JSON.stringify(raw),
    created_at: fetchTs,
  };
}
function pushAppend() { const r = mkRow.apply(null, arguments); if (r) append.push(r); }
function pushUpsert() { const r = mkRow.apply(null, arguments); if (r) upsert.push(r); }

// dash-platform <- platform-explorer /status (hourly, fetch-time ts, PE block height)
pushAppend('platform-explorer', 'dash-platform', 'identities_total', status.identitiesCount, status.identitiesCount, peHeight, fetchTs, status);
pushAppend('platform-explorer', 'dash-platform', 'documents_total', status.documentsCount, status.documentsCount, peHeight, fetchTs, status);
pushAppend('platform-explorer', 'dash-platform', 'data_contracts_total', status.dataContractsCount, status.dataContractsCount, peHeight, fetchTs, status);
pushAppend('platform-explorer', 'dash-platform', 'platform_total_credits', status.totalCredits, status.totalCredits, peHeight, fetchTs, status);
// dash-platform <- platform-explorer /transactions/shielded/statistic
pushAppend('platform-explorer', 'dash-platform', 'shielded_pool_balance_credits', shielded.poolBalance, shielded.poolBalance, peHeight, fetchTs, shielded);
pushAppend('platform-explorer', 'dash-platform', 'shielded_total_in_credits', shielded.totalShieldedIn, shielded.totalShieldedIn, peHeight, fetchTs, shielded);
pushAppend('platform-explorer', 'dash-platform', 'shielded_total_out_credits', shielded.totalShieldedOut, shielded.totalShieldedOut, peHeight, fetchTs, shielded);
pushAppend('platform-explorer', 'dash-platform', 'shielded_transitions_total', shielded.transitionsCount, shielded.transitionsCount, peHeight, fetchTs, shielded);

// zec chain-tip height <- blockchair (hourly, block-time ts, height = the height itself; coherent)
if (bc && Number.isFinite(bc.best_block_height)) {
  const bcTs = bcTimeToTs(bc.best_block_time) || fetchTs;
  pushAppend('blockchair', 'zec', 'zec_block_height', bc.best_block_height, bc.best_block_height, bc.best_block_height, bcTs,
             { best_block_height: bc.best_block_height, best_block_time: bc.best_block_time, best_block_hash: bc.best_block_hash });
} else { dropped.push('zec_block_height:no-source'); }

// zec supply <- ZecHub latest close (DAILY: ts = close date UTC midnight; height NULL; UPSERT)
if (zs && zs.supply !== undefined && zs.supply !== null) {
  const t = closeToTs(zs.close);
  if (t !== null) pushUpsert('zechub', 'zec', 'zec_shielded_supply', zs.supply, zs.supply, null, t, zs);
  else dropped.push('zec_shielded_supply:bad-close');
}
if (zt && zt.supply !== undefined && zt.supply !== null) {
  const t = closeToTs(zt.close);
  if (t !== null) pushUpsert('zechub', 'zec', 'zec_total_supply', zt.supply, zt.supply, null, t, zt);
  else dropped.push('zec_total_supply:bad-close');
}

if (append.length === 0 && upsert.length === 0) {
  throw new Error('onchain-snapshotter: no rows produced (all sources empty)');
}
const enc = (arr) => Buffer.from(JSON.stringify(arr), 'utf8').toString('base64');
return [{ json: { count_append: append.length, count_upsert: upsert.length, dropped, append_b64: enc(append), upsert_b64: enc(upsert) } }];
